import { FlowiseCallbackHandler } from '@vex_dev/sdk/flowise';

const handler = new FlowiseCallbackHandler({
  onRetrieverEnd: (output) => {
    const docs = output.documents || [];
    const scores = output.scores || [];

    docs.forEach((doc, i) => {
      if (scores[i] && scores[i] < 0.75) {
        console.warn(`Low relevance doc: score=${scores[i].toFixed(3)}, content=${doc.pageContent.substring(0, 100)}`);
      }
    });
  }
});

// Add to Flowise chatflow config
chatflow.callbacks = [handler];

const monitorRetriever = async (query: string, docs: Document[]) => {
  const embeddings = await getEmbeddings();
  const queryEmbedding = await embeddings.embedQuery(query);

  const avgDistance = docs.reduce((sum, doc) => {
    const docEmbedding = await embeddings.embedQuery(doc.pageContent);
    const distance = cosineDistance(queryEmbedding, docEmbedding);
    return sum + distance;
  }, 0) / docs.length;

  if (avgDistance > 0.3) {
    throw new Error(`High context drift: avg_distance=${avgDistance.toFixed(3)}`);
  }
};

const vexHandler = new FlowiseCallbackHandler({
  onRetrieverError: (error, input) => {
    console.error('Retriever failed:', error);
  },
  onRetrieverEnd: (output) => {
    if (!output.documents || output.documents.length === 0) {
      console.error('EMPTY RETRIEVAL:', output);
      throw new Error('Retriever returned no documents');
    }
  }
});

