const hybridRetriever = async (query: string) => {
  // Primary: Semantic search
  let docs = await vectorStore.similaritySearchWithScore(query, 3);
  docs = docs.filter(([doc, score]) => score < 0.8);

  // Fallback: Keyword search
  if (docs.length < 2) {
    const keywordDocs = await vectorStore.similaritySearch(
      query, 3, 
      { filter: { $text: { $search: query } } }
    );
    docs.push(...keywordDocs.map(doc => [doc, 0.85] as [Document, number]));
  }

  return docs.slice(0, 4);
};

