import { VexFlowise } from '@vex_dev/sdk/flowise';

// Install: npm install flowise @vex_dev/sdk

const vex = new VexFlowise({
  apiKey: process.env.VEX_API_KEY,
  project: 'flowise-rag',
  detectors: {
    retrieval_quality: {
      similarity_threshold: 0.78,
      min_docs: 2,
      max_distance: 0.25
    }
  }
});

// Add to Flowise chatflow configuration
const chatflow = await Flowise.loadFlowById('your-flow-id');
chatflow.callbacks = [vex];

// Auto-remediation rules
vex.on('low_retrieval_quality', async ({ query, docs, scores }) => {
  // Rerun with relaxed threshold
  const fallbackDocs = await chatflow.retriever.getRelevantDocuments(
    query, { similarityThreshold: 0.85 }
  );
  return { fixed: true, newDocs: fallbackDocs };
});
